module top_module(
    we,
    addr,
    din,
    dout,
    clk
);input we;
input [9:0] addr;
input [31:0] din;
output reg [31:0] dout;
input clk;

reg [31:0] mem_storage [0:1023]; // 1KB mem_storage with 32-bit wide data

always @(posedge clk) begin
    if (we) begin
        mem_storage[addr] <= din; // Write operation
    end
    dout <= mem_storage[addr]; // Read operation
end

endmodule
